#!/usr/bin/env python3
"""Genera Quiz_Adaptativo_2.html ... Quiz_Adaptativo_12.html"""
import os, re

ROOT = r'c:\Users\dudbi\Downloads\Curso_Introduccion_CDAT\Examen'

# Lee template base
with open(os.path.join(ROOT, 'Quiz_Adaptativo_1.html'), encoding='utf-8') as f:
    template = f.read()

# ─── Extraer secciones del template ───────────────────────────────────────
style_m = re.search(r'<style>.*?</style>', template, re.DOTALL)
style_block = style_m.group(0) if style_m else ''

# Todo lo que va dentro del body hasta el primer <script> de la lógica
body_m = re.search(r'(<body.*?)<script>', template, re.DOTALL)
body_html = body_m.group(1) if body_m else ''

# El motor JS (desde "const MAX_QUESTIONS" hasta </script>)
motor_m = re.search(r'(const MAX_QUESTIONS.*?)</script>\s*</body>', template, re.DOTALL)
motor_js = motor_m.group(1) if motor_m else ''

