def build_quiz(mod_num, cfg):
    # Update style color
    s = style_block.replace('--accent:#2563eb', f'--accent:{cfg["color"]}')
    s = s.replace('--accent-light:rgba(37,99,235,0.12)', f'--accent-light:{cfg["color"]}20')

    # Build preguntas JS
    qs = []
    for i, q in enumerate(cfg['preguntas']):
        ops = [f'{{"texto":"{o["t"].replace(chr(34), chr(39))}","correcto":{str(o["c"]).lower()}}}' for o in q['opciones']]
        f_line = f'formula:"{q.get("formula","").replace(chr(34),chr(39))}",' if q.get('formula') else ''
        qs.append(f"""  {{nivel:{q['nivel']},id:"c{mod_num}-n{q['nivel']}-{i+1}",
   texto:"{q['texto'].replace(chr(34),chr(39))}",
   {f_line}
   opciones:[{','.join(ops)}],
   feedback_ok:"{q['ok'].replace(chr(34),chr(39))}",
   feedback_bad:"{q['bad'].replace(chr(34),chr(39))}",
   pista:"{q['pista'].replace(chr(34),chr(39))}"
  }}""")

    config_js = f"""const QUIZ_CONFIG = {{
  titulo: "{cfg['titulo']}",
  icono: "{cfg['icono']}",
  moduloId: "{cfg['moduloId']}",
  xpBase: 40,
  preguntas: [
{',\n'.join(qs)}
  ]
}};"""

    # Update body HTML
    bh = body_html.replace('electric_bolt', cfg['icono'])
    bh = bh.replace('Quiz Adaptativo — Ley de Coulomb', cfg['titulo'])

    html = f"""<!DOCTYPE html>
<html lang="es">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>{cfg['titulo']}</title>
<link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap" rel="stylesheet">
<link href="https://fonts.googleapis.com/css2?family=Material+Symbols+Outlined:wght,FILL@100..700,0..1" rel="stylesheet">
{s}
</head>
{bh}
<script>
{config_js}

{motor_js}
</script>
</body>
</html>"""
    return html

for mod_num, cfg in MODULES.items():
    html = build_quiz(mod_num, cfg)
    path = os.path.join(ROOT, f'Quiz_Adaptativo_{mod_num}.html')
    with open(path, 'w', encoding='utf-8') as f:
        f.write(html)
    print(f'OK: Quiz_Adaptativo_{mod_num}.html ({len(html):,} bytes)')

print(f'\nTotal: {len(MODULES)} quizzes generados.')
